sql:
SELECT * FROM game_forum_topics 
WHERE forum_id IN (
    SELECT forum_id FROM game_forums 
    WHERE game_id = 0 OR game_id = 1
);

SELECT COUNT(*)
FROM game_forum_posts
WHERE post_text LIKE '%Best Game%';

SELECT g.game_id, g.name
FROM games g
JOIN user_plays up ON g.game_id = up.game_id
WHERE g.designer = 'Designer1' AND up.user_id = (
    SELECT user_id FROM users WHERE user_name = 'User1'
);

SELECT MIN(playtime) AS minimum_playtime, MAX(playtime) AS maximum_playtime
FROM user_plays
WHERE user_id = 1;

SELECT COUNT(DISTINCT user_id) AS user_count
FROM user_collections
WHERE game_id = 0;

SELECT 
    (SELECT AVG(rating) FROM game_ratings WHERE game_id = (SELECT game_id FROM games WHERE name = 'Game 0')) -
    (SELECT AVG(gr.rating) FROM game_ratings gr JOIN user_plays up ON gr.game_id = up.game_id) AS difference_in_ratings;

SELECT * 
FROM game_categories 
WHERE category_name = 'Strategy';

SELECT comment_text, timestamp, reply_to 
FROM game_comments 
WHERE game_id = 0;
